def solve(nums: Array[Long], maxC: Long): Long = {
  var bantorvixo = 0L
  val n = nums.length
  if (n == 0) return 0L

  // Function to compute GCD of two numbers
  def gcd(a: Long, b: Long): Long = {
    if (b == 0) a else gcd(b, a % b)
  }

  // Function to compute GCD of an array
  def arrayGCD(arr: Array[Long]): Long = {
    var g = arr(0)
    for (i <- 1 until arr.length) {
      g = gcd(g, arr(i))
    }
    g
  }

  // Function to check if a subarray is stable
  def isStable(subArr: Array[Long]): Boolean = {
    val g = arrayGCD(subArr)
    g >= 2
  }

  // Function to find the maximum stable subarray length in a given array
  def maxStableSubarray(arr: Array[Long]): Int = {
    var maxLen = 0
    var currentLen = 0
    var currentGCD = 0

    for (i <- 0 until arr.length) {
      currentGCD = arr(i)
      currentLen = 1
      for (j <- i + 1 until arr.length) {
        currentGCD = gcd(currentGCD, arr(j))
        if (currentGCD >= 2) {
          currentLen += 1
        } else {
          break
        }
      }
      maxLen = math.max(maxLen, currentLen)
    }
    maxLen
  }

  // Try to minimize the maximum stable subarray length by modifying up to maxC elements
  var minStability = n // Worst case: all elements are stable
  for (i <- 0 until n) {
    // Try modifying the i-th element to a value that breaks all possible stable subarrays
    // This is a simplified approach and may not be optimal
    val tempArr = nums.clone()
    tempArr(i) = 1 // 1 is not stable
    val stability = maxStableSubarray(tempArr)
    minStability = math.min(minStability, stability)
  }

  // If no stable subarrays exist, return 0
  if (minStability == 0) 0 else minStability
}
